import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class FileHandler {

    private static final String BASE_PATH = "C:\\data\\";

    public static void readFile(String fileName) {
        try {
            Path filePath = Paths.get(BASE_PATH, fileName).normalize().toAbsolutePath();
            if (!filePath.startsWith(Paths.get(BASE_PATH))) {
                System.err.println("Invalid file path specified.");
                return;
            }

            File file = filePath.toFile();
            byte[] fileContent = Files.readAllBytes(file.toPath());
            System.out.println(new String(fileContent));
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        String userInput = "../../../../../Windows/system.ini";
        readFile(userInput);
    }
}

